// ─── Dedup ───────────────────────────────────────────────────────────────────
/** Dedup candidates by DOI first, then title fingerprint. Drops unidentified rows. */ function dedupeCandidates(candidates) {
    const seen = new Set();
    const out = [];
    for (const c of candidates){
        const doi = normalizeDoi(c.doi);
        const titleKey = c.title ? titleFingerprint(c.title) : "";
        const key = doi ? `doi:${doi}` : `t:${titleKey}`;
        if (!titleKey && !doi) continue;
        if (!seen.has(key)) {
            seen.add(key);
            out.push({
                ...c,
                doi
            });
        }
    }
    return out;
}

/** Score a candidate's likelihood of being a match for `target`. */ function scoreCandidate(c, target) {
    const cTitle = (c.title ?? "").trim();
    const tTitle = (target.title ?? "").trim();
    if (!cTitle || !tTitle) return -1;
    const fpC = titleFingerprint(cTitle);
    const fpT = titleFingerprint(tTitle);
    const setC = new Set(fpC.split(" ").filter(Boolean));
    const setT = new Set(fpT.split(" ").filter(Boolean));
    let overlap = 0;
    for (const tok of setT)if (setC.has(tok)) overlap++;
    const overlapRatio = overlap / Math.max(1, setT.size);
    let score = overlapRatio * 70;
    if (target.year && c.year) {
        const diff = Math.abs(target.year - c.year);
        score += diff === 0 ? 15 : diff === 1 ? 8 : diff <= 3 ? 2 : -5;
    }
    if (c.doi) score += 8;
    if (c.abstract && stripJats(c.abstract)?.length) score += 5;
    if (c.authors && c.authors.length > 0) score += 2;
    switch(c.source){
        case "openalex":
            score += 4;
            break;
        case "semantic_scholar":
            score += 3;
            break;
        case "crossref":
            score += 2;
            break;
        case "europepmc":
            score += 1;
            break;
        case "arxiv":
            break;
        case "datacite":
            score -= 1;
            break;
        case "pubmed":
            score -= 1;
            break;
    }
    if (c.citationCount !== undefined && c.citationCount > 0) {
        score += Math.min(Math.log10(c.citationCount) * 2, 8);
    }
    if (c.influentialCitationCount !== undefined && c.influentialCitationCount > 0) {
        score += Math.min(c.influentialCitationCount * 0.5, 4);
    }
    if (c.tldr) score += 2;
    return score;
}
/**
 * Pick the best candidate. Returns null when no candidate clears the similarity floor
 * (score < `minScore`, default 35).
 */ function pickBestCandidate(candidates, target, minScore = 35) {
    if (!candidates.length) return null;
    let best = null;
    let bestScore = -Infinity;
    for (const c of candidates){
        const s = scoreCandidate(c, target);
        if (s > bestScore) {
            bestScore = s;
            best = c;
        }
    }
    return bestScore < minScore ? null : best;
}

const BOOK_CHAPTER_TYPES = new Set([
    "book-chapter",
    "book-section",
    "book-part",
    "reference-entry",
    "book",
    "monograph",
    "edited-book",
    "reference-book"
]);
/** Drop book chapters and book-like publication types. */ function filterBookChapters(candidates) {
    return candidates.filter((c)=>{
        if (!c.publicationType) return true;
        return !BOOK_CHAPTER_TYPES.has(c.publicationType);
    });
}
/** Drop candidates whose abstract is missing or shorter than `minLength` chars. */ function filterShortAbstracts(candidates, minLength = 200) {
    return candidates.filter((c)=>typeof c.abstract === "string" && c.abstract.length >= minLength);
}
/** Compose package filters + caller-supplied filters into a single pipeline. */ function applyQualityFilters(candidates, opts = {}) {
    let out = filterBookChapters(candidates);
    for (const fn of opts.extraFilters ?? [])out = fn(out);
    if (!opts.skipAbstractCheck) {
        out = filterShortAbstracts(out, opts.minAbstractLength ?? 200);
    }
    return out;
}

/**
 * Run `fn` across `items` with a bounded concurrency window.
 * Results are returned in input order (not completion order).
 */ async function mapLimit(items, limit, fn) {
    const results = new Array(items.length);
    let next = 0;
    const workers = new Array(Math.min(limit, items.length)).fill(0).map(async ()=>{
        while(true){
            const idx = next++;
            if (idx >= items.length) break;
            results[idx] = await fn(items[idx], idx);
        }
    });
    await Promise.all(workers);
    return results;
}

/**
 * Enrich a candidate into full `PaperDetails`:
 *  - Attached `_enrichedAbstract` → use it directly.
 *  - DOI present → re-fetch from Crossref.
 *  - PubMed candidate → pull DOI + abstract from efetch.
 *  - Scholar candidate → re-fetch with richer field set.
 *  - Fallback: DOI content negotiation + Unpaywall OA.
 */ async function fetchPaperDetails(candidate) {
    const hints = candidate;
    if (hints._enrichedAbstract) {
        return {
            ...candidate,
            abstract: hints._enrichedAbstract,
            year: candidate.year ?? hints._enrichedYear,
            journal: candidate.journal ?? hints._enrichedVenue,
            authors: candidate.authors ?? hints._enrichedAuthors ?? [],
            doi: normalizeDoi(candidate.doi)
        };
    }
    if (candidate.doi) {
        try {
            const client = new CrossrefClient({
                mailto: process.env.RESEARCH_MAILTO
            });
            const item = await client.getWork(candidate.doi);
            return {
                ...candidate,
                title: candidate.title || (Array.isArray(item.title) ? item.title[0] ?? "" : item.title ?? ""),
                abstract: stripJats(item.abstract) ?? candidate.abstract ?? "Abstract not available",
                authors: candidate.authors ?? (item.author ?? []).map((a)=>`${a.given ?? ""} ${a.family ?? ""}`.trim()).filter((s)=>s.length > 0),
                year: candidate.year ?? item.published?.["date-parts"]?.[0]?.[0],
                journal: candidate.journal ?? (Array.isArray(item["container-title"]) ? item["container-title"][0] : item["container-title"])
            };
        } catch (err) {
            console.warn("[fetchPaperDetails] Crossref enrichment failed:", err);
        }
    }
    if (candidate.source === "pubmed" && candidate.url) {
        const pmid = candidate.url.match(/\/(\d+)\//)?.[1];
        if (pmid) {
            const extra = await fetchPubMedDoiAndAbstractByPmid(pmid);
            return {
                ...candidate,
                doi: candidate.doi ?? extra.doi,
                abstract: extra.abstract ?? candidate.abstract ?? "Abstract not available",
                authors: candidate.authors ?? []
            };
        }
    }
    if (candidate.source === "semantic_scholar" && (candidate.doi || candidate.s2PaperId)) {
        const id = candidate.doi ? `DOI:${candidate.doi}` : candidate.s2PaperId;
        const enriched = await getSemanticScholarPaper(id);
        if (enriched) {
            return {
                ...candidate,
                ...enriched,
                oaUrl: candidate.oaUrl ?? enriched.openAccessPdfUrl,
                abstract: enriched.abstract ?? candidate.abstract ?? "Abstract not available",
                authors: enriched.authors?.length ? enriched.authors : candidate.authors ?? []
            };
        }
    }
    if (candidate.doi) {
        const doiData = await fetchDoiMetadata(candidate.doi);
        if (doiData) {
            const merged = {
                ...candidate,
                title: candidate.title || doiData.title || "Untitled",
                abstract: stripJats(candidate.abstract ?? doiData.abstract) ?? "Abstract not available",
                authors: candidate.authors?.length ? candidate.authors : doiData.authors ?? [],
                year: candidate.year ?? doiData.year,
                journal: candidate.journal ?? doiData.journal,
                doi: normalizeDoi(candidate.doi)
            };
            const oa = await getUnpaywallOaUrl(candidate.doi);
            return {
                ...merged,
                oaUrl: oa?.oaUrl,
                oaStatus: oa?.oaStatus
            };
        }
    }
    const result = {
        ...candidate,
        abstract: stripJats(candidate.abstract) ?? "Abstract not available",
        authors: candidate.authors ?? [],
        doi: normalizeDoi(candidate.doi)
    };
    if (candidate.doi) {
        const oa = await getUnpaywallOaUrl(candidate.doi);
        if (oa) {
            result.oaUrl = oa.oaUrl;
            result.oaStatus = oa.oaStatus;
        }
    }
    return result;
}
/** Resolve paper metadata across all sources by title (+ optional year). */ async function resolvePaperByTitle(title, opts = {}) {
    const limit = opts.limitPerSource ?? 8;
    const [crossref, pubmed, semantic, openalex, arxiv, europepmc] = await Promise.all([
        searchCrossref(title, limit),
        searchPubMed(title, limit),
        searchSemanticScholar(title, limit),
        searchOpenAlex(title, limit),
        searchArxiv(title, limit),
        searchEuropePmc(title, limit)
    ]);
    const candidates = dedupeCandidates([
        ...crossref,
        ...pubmed,
        ...semantic,
        ...openalex,
        ...arxiv,
        ...europepmc
    ]);
    const best = pickBestCandidate(candidates, {
        title,
        year: opts.year
    }, opts.minScore);
    if (!best) return null;
    const details = await fetchPaperDetails(best);
    if (details.source === "pubmed" && details.url) {
        const pmid = details.url.match(/\/(\d+)\//)?.[1];
        if (pmid) {
            const extra = await fetchPubMedDoiAndAbstractByPmid(pmid);
            return {
                ...details,
                doi: details.doi ?? extra.doi,
                abstract: details.abstract && details.abstract !== "Abstract not available" ? details.abstract : extra.abstract ?? details.abstract,
                authors: details.authors ?? []
            };
        }
    }
    return {
        ...details,
        abstract: stripJats(details.abstract) ?? "Abstract not available",
        doi: normalizeDoi(details.doi)
    };
}

